field_name = #{fieldName}, field_label = #{fieldLabel}, field_type = #{fieldType}, sort_order = #{sortOrder}, is_visible = #{isVisible}, width = #{width}, align = #{align}, dict_type = #{dictType}, update_time = NOW()
